from collections import deque

def bfs(graph, start):
    q = deque([start])
    seen = {start}
    out = []
    while q:
        v = q.popleft()
        out.append(v)
        for n in graph.get(v, []):
            if n not in seen:
                seen.add(n); q.append(n)
    return out

def dfs(graph, start):
    seen=set(); out=[]
    def visit(v):
        seen.add(v); out.append(v)
        for n in graph.get(v, []):
            if n not in seen: visit(n)
    visit(start)
    return out

