# C0668 · A* (pathfinding) (Avanzado, Algoritmos)
import heapq

def solve(grid, start, goal):
    # grid: list[list[int]] 0=free 1=wall
    w, h = len(grid[0]), len(grid)
    def hcost(a,b): return abs(a[0]-b[0]) + abs(a[1]-b[1])
    def neighbors(p):
        x,y=p
        for dx,dy in ((1,0),(-1,0),(0,1),(0,-1)):
            nx,ny=x+dx,y+dy
            if 0<=nx<w and 0<=ny<h and grid[ny][nx]==0:
                yield (nx,ny)
    openh=[]
    heapq.heappush(openh,(0,start))
    came={}
    g={start:0}
    while openh:
        _, cur = heapq.heappop(openh)
        if cur==goal:
            # reconstruct
            path=[cur]
            while cur in came:
                cur=came[cur]; path.append(cur)
            return list(reversed(path))
        for nb in neighbors(cur):
            ng = g[cur]+1
            if nb not in g or ng<g[nb]:
                g[nb]=ng
                came[nb]=cur
                f = ng + hcost(nb,goal)
                heapq.heappush(openh,(f,nb))
    return []

