# Python: lectura simple de teclas en terminal (Windows/Linux/macOS)
import os, sys

def _read_key():
    if os.name == "nt":
        import msvcrt
        return msvcrt.getwch()
    import termios, tty
    fd = sys.stdin.fileno()
    old = termios.tcgetattr(fd)
    try:
        tty.setraw(fd)
        ch = sys.stdin.read(1)
        return ch
    finally:
        termios.tcsetattr(fd, termios.TCSADRAIN, old)

def solve():
    print("Presiona WASD (q para salir).")
    while True:
        k = _read_key()
        if k.lower() == "q": break
        if k.lower() == "w": print("Mover: arriba")
        if k.lower() == "s": print("Mover: abajo")
        if k.lower() == "a": print("Mover: izquierda")
        if k.lower() == "d": print("Mover: derecha")
        if k in ("\r","\n"): print("Acción: confirmar")
        if k == "\x1b": print("Acción: cancelar")

